// Define the "Duck" shape
interface Duck {
  quack(): void;
  fly(): void;
}

// This function expects a Duck
function letItFly(duck: Duck) {
  duck.fly();
}

// Object A: Explicitly implements the interface
const realDuck: Duck = {
  quack: () => console.log("Quack"),
  fly: () => console.log("Flying")
};

// Object B: Does NOT declare it is a Duck, but has the same shape
const robotDuck = {
  quack: () => console.log("Beep"),
  fly: () => console.log("Hovering")
};

// TypeScript accepts both because they "look like a duck"
letItFly(realDuck);   // ✅ Valid
letItFly(robotDuck);  // ✅ Valid (Structural/Duck Typing)

// This would fail because it lacks the 'fly' method
letItFly({ quack: () => {} }); // ❌ Error: Property 'fly' is missing
```

